## 2️⃣  `pcapng_stubs.cpp` – the C/C++ glue

```cpp
/*--------------------------------------------------------------------
   pcapng_stubs.cpp  –  C++ stubs for the OCaml libpcapng binding
   --------------------------------------------------------------------
   Compile with:
     ocamlc -c -custom -ccopt -std=c++17 -I +ocaml pcapng_stubs.cpp
   Link with:
     ocamlc -custom -o myprog unix.cma pcapng.cma pcapng_stubs.o -lpcapng
--------------------------------------------------------------------*/

#define CAML_NAME_SPACE   /* avoid name clashes with C++ std:: */
#include <caml/mlvalues.h>
#include <caml/memory.h>
#include <caml/alloc.h>
#include <caml/custom.h>
#include <caml/callback.h>
#include <caml/fail.h>
#include <caml/bigarray.h>

#include <cstdint>
#include <memory>
#include <vector>
#include <string>
#include <cstring>   // memcpy
#include <exception>

/* ------------------------------------------------------------------
   libpcapng C++ API (simplified for this example)
   ------------------------------------------------------------------ */
namespace pcapng {

struct Frame {
    int64_t timestamp;      // nanoseconds since epoch
    uint32_t captured_len;  // bytes stored in the file
    uint32_t orig_len;      // original packet length
    const uint8_t* data;    // pointer into internal buffer (valid until next frame)
};

class Iterator {
public:
    explicit Iterator(const std::string& filename);
    bool   has_next() const;
    Frame  next();                // advances iterator, returns current frame
    void   rewind();              // reset to beginning
    size_t count() const;         // total number of frames (may be O(N))
};

} // namespace pcapng

/* ------------------------------------------------------------------
   OCaml custom block that wraps the C++ iterator
   ------------------------------------------------------------------ */
struct pcapng_handle {
    std::unique_ptr<pcapng::Iterator> iter;
    bool closed;   // true after close/finaliser, to detect misuse
    pcapng_handle(pcapng::Iterator* i) : iter(i), closed(false) {}
};

static void pcapng_finalize(value v) {
    pcapng_handle* h = reinterpret_cast<pcapng_handle*>(Data_custom_val(v));
    if (h && !h->closed) {
        // unique_ptr will automatically free the iterator
        h->closed = true;
    }
}

/* Register the custom operations */
static struct custom_operations pcapng_ops = {
    "org.example.pcapng",
    pcapng_finalize,
    custom_compare_default,
    custom_hash_default,
    custom_serialize_default,
    custom_deserialize_default,
    custom_fixed_length_default
};

/* ------------------------------------------------------------------
   Helper to allocate a fresh OCaml handle (custom block)
   ------------------------------------------------------------------ */
static value alloc_handle(pcapng::Iterator* it) {
    CAMLparam0();
    value v = caml_alloc_custom(&pcapng_ops, sizeof(pcapng_handle*), 0, 1);
    pcapng_handle* h = new pcapng_handle(it);
    Store_custom_val(v, reinterpret_cast<intnat>(h));
    CAMLreturn(v);
}

/* ------------------------------------------------------------------
   Accessor – get the C++ handle from an OCaml value, checking that it
   hasn't been closed.
   ------------------------------------------------------------------ */
static pcapng_handle* get_handle(value v) {
    pcapng_handle* h = reinterpret_cast<pcapng_handle*>(Data_custom_val(v));
    if (h == nullptr || h->closed) caml_failwith("Pcapng.handle is closed");
    return h;
}

/* ------------------------------------------------------------------
   OCaml primitives
   ------------------------------------------------------------------ */

/* val open_file : string -> t */
extern "C" CAMLprim value caml_pcapng_open_file(value v_path) {
    CAMLparam1(v_path);
    CAMLlocal1(v_res);
    const char* path = String_val(v_path);
    try {
        auto* it = new pcapng::Iterator(path);
        v_res = alloc_handle(it);
    } catch (const std::exception& e) {
        caml_failwith(e.what());
    }
    CAMLreturn(v_res);
}

/* val close : t -> unit */
extern "C" CAMLprim value caml_pcapng_close(value v_handle) {
    CAMLparam1(v_handle);
    pcapng_handle* h = reinterpret_cast<pcapng_handle*>(Data_custom_val(v_handle));
    if (h && !h->closed) {
        // unique_ptr will delete the iterator
        h->closed = true;
    }
    CAMLreturn(Val_unit);
}

/* ------------------------------------------------------------------
   Build an OCaml record of type `frame` from a pcapng::Frame.
   The layout must match the .mli definition (timestamp, captured_len,
   orig_len, data).
   ------------------------------------------------------------------ */
static value caml_val_of_frame(const pcapng::Frame& f) {
    CAMLparam0();
    CAMLlocal4(v_ts, v_caplen, v_origlen, v_data);
    CAMLlocal1(v_frame);

    /* timestamp – int64 */
    v_ts = caml_copy_int64(f.timestamp);

    /* captured_len – int (fits in OCaml int on 64‑bit platforms) */
    v_caplen = Val_int(static_cast<int>(f.captured_len));

    /* orig_len – int */
    v_origlen = Val_int(static_cast<int>(f.orig_len));

    /* data – bytes */
    v_data = caml_alloc_initialized_string(f.captured_len,
                                           reinterpret_cast<const char*>(f.data));

    /* Allocate the record (4 fields) */
    v_frame = caml_alloc(4, 0);          // tag 0 = record
    Store_field(v_frame, 0, v_ts);
    Store_field(v_frame, 1, v_caplen);
    Store_field(v_frame, 2, v_origlen);
    Store_field(v_frame, 3, v_data);

    CAMLreturn(v_frame);
}

/* ------------------------------------------------------------------
   val iter : t -> (frame -> unit) -> unit
   ------------------------------------------------------------------ */
extern "C" CAMLprim value caml_pcapng_iter(value v_handle, value v_cb) {
    CAMLparam2(v_handle, v_cb);
    CAMLlocal1(v_frame);
    pcapng_handle* h = get_handle(v_handle);
    pcapng::Iterator* it = h->iter.get();

    /* The loop may be long; we release the OCaml runtime while we are
       *not* calling back into OCaml, to allow other OCaml threads to run.
       * However we must reacquire it before each callback. */
    while (it->has_next()) {
        pcapng::Frame f = it->next();

        /* Build the OCaml representation */
        v_frame = caml_val_of_frame(f);

        /* Call the user callback.  Use caml_callback_exn so we can
           detect exceptions. */
        caml_acquire_runtime_system();          // reacquire for the call
        value result = caml_callback_exn(v_cb, v_frame);
        caml_release_runtime_system();          // release again

        if (Is_exception_result(result)) {
            /* Propagate the OCaml exception to the caller. */
            caml_raise(result);
        }
    }
    CAMLreturn(Val_unit);
}

/* ------------------------------------------------------------------
   val fold : t -> ('a -> frame -> 'a) -> 'a -> 'a
   ------------------------------------------------------------------ */
extern "C" CAMLprim value caml_pcapng_fold(value v_handle,
                                          value v_f,
                                          value v_acc) {
    CAMLparam3(v_handle, v_f, v_acc);
    CAMLlocal2(v_acc_cur, v_frame);
    pcapng_handle* h = get_handle(v_handle);
    pcapng::Iterator* it = h->iter.get();

    while (it->has_next()) {
        pcapng::Frame f = it->next();
        v_frame = caml_val_of_frame(f);

        caml_acquire_runtime_system();
        value res = caml_callback_exn(v_f, v_acc_cur = v_acc, v_frame);
        caml_release_runtime_system();

        if (Is_exception_result(res)) caml_raise(res);
        v_acc = res;   // new accumulator
    }
    CAMLreturn(v_acc);
}

/* ------------------------------------------------------------------
   val nth_frame : t -> int -> frame option
   ------------------------------------------------------------------ */
extern "C" CAMLprim value caml_pcapng_nth_frame(value v_handle, value v_idx) {
    CAMLparam2(v_handle, v_idx);
    CAMLlocal2(v_some, v_frame);
    pcapng_handle* h = get_handle(v_handle);
    pcapng::Iterator* it = h->iter.get();

    int n = Int_val(v_idx);
    if (n < 0) caml_failwith("nth_frame: negative index");

    int i = 0;
    while (it->has_next()) {
        pcapng::Frame f = it->next();
        if (i == n) {
            v_frame = caml_val_of_frame(f);
            v_some = caml_alloc(1, 0);            // Some
            Store_field(v_some, 0, v_frame);
            CAMLreturn(v_some);
        }
        ++i;
    }
    /* not found → None */
    CAMLreturn(caml_alloc(0, 0));
}

/* ------------------------------------------------------------------
   val frame_count : t -> int
   ------------------------------------------------------------------ */
extern "C" CAMLprim value caml_pcapng_frame_count(value v_handle) {
    CAMLparam1(v_handle);
    pcapng_handle* h = get_handle(v_handle);
    pcapng::Iterator* it = h->iter.get();

    /* The iterator class provides a cheap count() if the library knows it,
       otherwise we fall back to a full scan.  In either case we must rewind
       the iterator afterwards. */
    size_t cnt = it->count();
    it->rewind();

    CAMLreturn(Val_int(static_cast<int>(cnt)));
}

/* ------------------------------------------------------------------
   Register the primitives (for ocamlc -custom linking)
   ------------------------------------------------------------------ */
static struct caml_named_value caml_pcapng_named_values[] = {
    {"pcapng_open_file",   caml_pcapng_open_file},
    {"pcapng_close",       caml_pcapng_close},
    {"pcapng_iter",        caml_pcapng_iter},
    {"pcapng_fold",        caml_pcapng_fold},
    {"pcapng_nth_frame",   caml_pcapng_nth_frame},
    {"pcapng_frame_count", caml_pcapng_frame_count},
    {NULL, NULL}
};

extern "C" CAMLprim value caml_pcapng_register_primitives(value unit) {
    CAMLparam1(unit);
    for (int i = 0; caml_pcapng_named_values[i].name != NULL; ++i) {
        caml_register_named_value(caml_pcapng_named_values[i].name,
                                  caml_pcapng_named_values[i].fun);
    }
    CAMLreturn(Val_unit);
}
```

### How the stub works

| OCaml side | C++ side |
|------------|----------|
| `type t` is a **custom block** that stores a pointer to `pcapng_handle`. | `pcapng_handle` contains a `std::unique_ptr<pcapng::Iterator>` and a flag `closed`. |
| `open_file` allocates the custom block and stores a new `Iterator`. | If the C++ constructor throws, we translate the exception into `Failure`. |
| `iter` receives an OCaml callback (`v_cb`). Inside the C++ loop we: <br> 1. Build an OCaml `frame` value (`caml_val_of_frame`). <br> 2. Call `caml_callback_exn` with the callback and the frame. <br> 3. Detect an exception (`Is_exception_result`) and re‑raise it. | The loop releases the OCaml runtime (`caml_release_runtime_system`) while it is *not* calling back, then reacquires it right before the callback.  This lets other OCaml threads run while the iterator is doing its own work. |
| `fold`, `nth_frame`, `frame_count` are thin wrappers built on top of the same iterator. | All functions check that the handle is still open; if not, they raise `Failure "Pcapng.handle is closed"`. |
| The custom finaliser (`pcapng_finalize`) marks the handle as closed; the `close` primitive does the same. | Because the `Iterator` lives inside a `unique_ptr`, the memory is automatically reclaimed when the handle is destroyed or closed. |

